#include <stdio.h>

int square(int x) {
    return x * x;
}

int add(int a, int b) {
    return a + b;
}

// Pointer ile parametre degistirme (referansla gecirme)
void increment(int* value) {
    (*value)++;
}

// Birden fazla deger dondurme: pointer ile
void minMax(int arr[], int size, int* min, int* max) {
    *min = arr[0];
    *max = arr[0];

    for (int i = 0; i < size; i++) {
        if (arr[i] < *min) *min = arr[i];
        if (arr[i] > *max) *max = arr[i];
    }
}

int main() {
    printf("Kare: %d\n", square(5));
    printf("Toplam: %d\n", add(3, 7));

    int x = 10;
    printf("\nOnce: %d\n", x);
    increment(&x);
    printf("Sonra: %d\n", x);

    int numbers[] = {4, 12, 7, 23, 9, 1};
    int min, max;
    minMax(numbers, 6, &min, &max);
    printf("\nMin: %d, Max: %d\n", min, max);

    return 0;
}
